(function(){"use strict";if(typeof window.matchMedia==="function"&&window.matchMedia("(prefers-reduced-motion: reduce)").matches){return}var stack=null;var liveCount=0;var MAX_LIVE=3;var INTERVAL_MIN_MS=8e3;var INTERVAL_MAX_MS=22e3;var ACTORS=[{name:"Alex",initials:"AP",bg:"linear-gradient(135deg,#4a5cf0,#c44ef0)"},{name:"Priya",initials:"PS",bg:"linear-gradient(135deg,#f0824a,#f04a8e)"},{name:"Marco",initials:"MV",bg:"linear-gradient(135deg,#10b981,#06b6d4)"},{name:"Lin",initials:"LZ",bg:"linear-gradient(135deg,#ec4899,#a855f7)"},{name:"Sam",initials:"SK",bg:"linear-gradient(135deg,#f59e0b,#ef4444)"},{name:"Jasmin",initials:"JA",bg:"linear-gradient(135deg,#3b82f6,#1d4ed8)"},{name:"Ravi",initials:"RB",bg:"linear-gradient(135deg,#14b8a6,#0891b2)"},{name:"Noa",initials:"NH",bg:"linear-gradient(135deg,#a78bfa,#7c3aed)"},{name:"Dan",initials:"DM",bg:"linear-gradient(135deg,#fb923c,#dc2626)"},{name:"Yuki",initials:"YT",bg:"linear-gradient(135deg,#22c55e,#65a30d)"},{name:"Kai",initials:"KN",bg:"linear-gradient(135deg,#06b6d4,#0d9488)"},{name:"Mia",initials:"MR",bg:"linear-gradient(135deg,#f472b6,#db2777)"}];var ACTIONS=[{verb:"just played",emoji:"\u{1F3AE}"},{verb:"beat their best on",emoji:"\u{1F3C6}"},{verb:"unlocked a trophy in",emoji:"\u2728"},{verb:"started a streak with",emoji:"\u{1F525}"},{verb:"voted hot on",emoji:"\u{1F4A5}"}];function esc(s){return String(s==null?"":s).replace(/[&<>"']/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]})}function pick(arr){return arr[Math.floor(Math.random()*arr.length)]}function pickGame(){var pool=[];function add(arr){if(!arr||!arr.length)return;for(var i=0;i<arr.length;i++){if(arr[i]&&arr[i].name)pool.push({name:arr[i].name,url:arr[i].url||""})}}add(window.WGP_CATALOG);add(window.WG_RELATED_GAMES);add(window.WG_PUBLISHER_GAMES);add(window.__surprisePool);var cur=window.WG_GAME&&window.WG_GAME.name||null;if(cur&&pool.length){var others=pool.filter(function(g2){return g2.name!==cur});if(others.length)pool=others}if(pool.length){var g=pool[Math.floor(Math.random()*pool.length)];return{name:g.name,url:g.url||""}}if(cur)return{name:cur,url:window.WG_GAME&&window.WG_GAME.url||""};return{name:"a game",url:""}}function modalOpen(){return!!(window.wgpModal&&window.wgpModal.isOpen())}function push(){if(!stack||liveCount>=MAX_LIVE||modalOpen())return;var actor=pick(ACTORS);var action=pick(ACTIONS);var game=pickGame();var toast=document.createElement(game.url?"a":"div");toast.className="ghost-toast"+(game.url?" is-link":"");if(game.url){toast.href=game.url;toast.setAttribute("aria-label",actor.name+" "+action.verb+" "+game.name+" - open game")}toast.innerHTML='<span class="ghost-toast-avatar" style="background:'+esc(actor.bg)+'" aria-hidden="true">'+esc(actor.initials)+'</span><span class="ghost-toast-emoji" aria-hidden="true">'+action.emoji+'</span><span class="ghost-toast-body"><strong>'+esc(actor.name)+"</strong> "+esc(action.verb)+" <em>"+esc(game.name)+"</em></span>";stack.appendChild(toast);liveCount++;requestAnimationFrame(function(){toast.classList.add("is-open")});setTimeout(function(){toast.classList.remove("is-open");setTimeout(function(){if(toast.parentNode===stack)stack.removeChild(toast);liveCount--},320)},5800)}function tick(){push();var delay=INTERVAL_MIN_MS+Math.random()*(INTERVAL_MAX_MS-INTERVAL_MIN_MS);setTimeout(tick,delay)}function boot(){stack=document.getElementById("ghostStack");if(!stack)return;setTimeout(tick,6e3)}if(document.readyState!=="loading")boot();else document.addEventListener("DOMContentLoaded",boot)})();
